# Generated by AutoTestGen ⚙️ — Powered by Team RRR 🚀

from utilities.utils import Util

class AllowedIndicatorsAPI:
    def __init__(self):
        self.allowed_types = ["domain", "ip", "url", "email", "sha1", "sha256", "md5", "cve", "ipv4_cidr"]

    def generate_random_indicators(self, indicator_type, count=1):
        indicators = []
        for _ in range(count):
            if indicator_type == "domain":
                indicators.append(Util.getUniqueName() + ".com")
            elif indicator_type == "ip":
                indicators.append(".".join(map(str, (Util.getRandomNumber(1, 255) for _ in range(4)))))
            elif indicator_type == "url":
                indicators.append("http://" + Util.getUniqueName() + ".com")
            elif indicator_type == "email":
                indicators.append(Util.getUniqueName() + "@example.com")
            elif indicator_type in ["sha1", "sha256", "md5"]:
                indicators.append(Util.getRandomHexString(64 if indicator_type == "sha256" else 40 if indicator_type == "sha1" else 32))
            elif indicator_type == "cve":
                indicators.append("CVE-" + str(Util.getRandomNumber(2000, 2022)) + "-" + str(Util.getRandomNumber(1000, 9999)))
            elif indicator_type == "ipv4_cidr":
                indicators.append(".".join(map(str, (Util.getRandomNumber(1, 255) for _ in range(4)))) + "/" + str(Util.getRandomNumber(1, 32)))
        return ",".join(indicators)

    def post_allowed_indicators_payload(self, indicator_type, count=1):
        return {
            "threat_indicators": self.generate_random_indicators(indicator_type, count)
        }

    def get_allowed_indicators_params(self, page=1, page_size=10, indicator_type=None, value=None):
        params = {
            "page": page,
            "page_size": page_size
        }
        if indicator_type:
            params["type"] = indicator_type
        if value:
            params["value"] = value
        return params
